// Parse Fathom email for meeting data (from Gmail API full format)
const email = $input.all()[0].json;

// Decode body from Gmail API full format
function decodeBase64Url(str) {
  if (!str) return '';
  const b64 = str.replace(/-/g, '+').replace(/_/g, '/');
  return Buffer.from(b64, 'base64').toString('utf-8');
}

function extractBody(payload) {
  let html = '';
  let text = '';

  if (payload.body && payload.body.data) {
    const decoded = decodeBase64Url(payload.body.data);
    if (payload.mimeType === 'text/html') html = decoded;
    else if (payload.mimeType === 'text/plain') text = decoded;
  }

  if (payload.parts) {
    for (const part of payload.parts) {
      if (part.mimeType === 'text/plain' && part.body && part.body.data) {
        text = decodeBase64Url(part.body.data);
      } else if (part.mimeType === 'text/html' && part.body && part.body.data) {
        html = decodeBase64Url(part.body.data);
      } else if (part.parts) {
        const nested = extractBody(part);
        if (nested.text) text = nested.text;
        if (nested.html) html = nested.html;
      }
    }
  }

  return { text, html };
}

const { text: plainText, html: htmlBody } = extractBody(email.payload || {});

let body = plainText;

if (!body && htmlBody) {
  body = htmlBody
    .replace(/<style[^>]*>[\s\S]*?<\/style>/gi, '')
    .replace(/<script[^>]*>[\s\S]*?<\/script>/gi, '')
    .replace(/<br\s*\/?>/gi, '\n')
    .replace(/<\/p>/gi, '\n\n')
    .replace(/<\/div>/gi, '\n')
    .replace(/<\/li>/gi, '\n')
    .replace(/<\/h[1-6]>/gi, '\n\n')
    .replace(/<[^>]+>/g, '')
    .replace(/&nbsp;/g, ' ')
    .replace(/&amp;/g, '&')
    .replace(/&lt;/g, '<')
    .replace(/&gt;/g, '>')
    .replace(/&quot;/g, '"')
    .replace(/&#39;/g, "'")
    .replace(/\n{3,}/g, '\n\n')
    .trim();
}

if (!body) body = email.snippet || '';

const headers = (email.payload && email.payload.headers) || [];
const subjectHeader = headers.find(h => h.name.toLowerCase() === 'subject');
const dateHeader = headers.find(h => h.name.toLowerCase() === 'date');
const subject = subjectHeader ? subjectHeader.value : '';

let meetingTitle = subject
  .replace(/^Recap of your meeting with\s*/i, '')
  .replace(/^(Meeting notes:|Meeting summary:|Notes from)\s*/i, '')
  .replace(/\s*-\s*(Meeting Summary|Notes|Recap)$/i, '')
  .trim();

const meetingDate = dateHeader ? dateHeader.value : new Date().toISOString();

const attendeePatterns = [
  /Attendees?:?\s*([^\n]+)/i,
  /Participants?:?\s*([^\n]+)/i,
  /With:?\s*([^\n]+)/i,
  /Between:?\s*([^\n]+)/i
];

let attendees = '';
for (const pattern of attendeePatterns) {
  const match = body.match(pattern);
  if (match) { attendees = match[1].trim(); break; }
}

const summaryMatch = body.match(/(?:Summary|Overview|Recap)[:\s]*\n([\s\S]*?)(?=\n(?:Action Items|Key Points|Decisions|Highlights|$))/i);
const summary = summaryMatch ? summaryMatch[1].trim() : body.substring(0, 4000);

const actionItemsMatch = body.match(/(?:Action Items|Next Steps|Tasks|Follow[- ]?ups?)[:\s]*\n([\s\S]*?)(?=\n(?:Key Points|Decisions|Summary|Highlights|$))/i);
const actionItems = actionItemsMatch ? actionItemsMatch[1].trim() : 'None auto-detected';

const emailDomains = [];
const emailRegex = /[\w.-]+@([\w.-]+\.\w+)/g;
let emailMatch;
while ((emailMatch = emailRegex.exec(attendees + ' ' + body)) !== null) {
  const domain = emailMatch[1].toLowerCase();
  if (!domain.includes('gmail.com') && !domain.includes('fathom') && !domain.includes('revopsinflection')) {
    emailDomains.push(domain);
  }
}

return [{
  json: {
    meeting_title: meetingTitle || subject,
    meeting_date: meetingDate,
    attendees: attendees,
    attendee_domains: [...new Set(emailDomains)],
    fathom_summary: summary,
    fathom_action_items: actionItems,
    raw_email_body: body,
    email_id: email.id
  }
}];

const data = $input.all()[0].json;
const domains = data.attendee_domains || [];

// Try domain-based lookup first
let lookupType = 'email_domain';
let lookupValue = domains[0] || '';

// If no domain found, try matching client name from meeting title
// Fathom subjects: "Recap of your meeting with Blackthorn" -> "Blackthorn"
if (!lookupValue || lookupValue === 'unknown') {
  const title = data.meeting_title || '';
  if (title) {
    lookupType = 'client_name';
    lookupValue = title;
  }
}

if (!lookupValue) lookupValue = 'unknown';

return [{
  json: {
    ...data,
    lookup_type: lookupType,
    lookup_value: lookupValue
  }
}];

const emailData = $('Parse Fathom Email').first().json;
const clientData = $input.all()[0].json;

// Build system prompt for ai-api-wrapper
const system_prompt = `You are a senior RevOps consultant's AI assistant. You analyze meeting transcripts and summaries from B2B SaaS client calls to extract actionable intelligence.

Your analysis must be:
- Exhaustive on action items (Fathom's auto-detection misses ~30% of implicit commitments)
- Clear on ownership (consultant vs. client vs. third party)
- Specific on deadlines (extract explicit dates; infer reasonable deadlines for items without them)
- Alert to risk signals (scope creep, stakeholder misalignment, budget concerns, timeline pressure)

Output format must be structured JSON for downstream automation.`;

const clientName = clientData.client_name || 'Unknown Client';

// Build user prompt from template
const user_prompt = `Analyze this meeting summary and extract all actionable intelligence.

**Meeting Info:**
- Title: ${emailData.meeting_title}
- Date: ${emailData.meeting_date}
- Attendees: ${emailData.attendees || 'Not specified'}
- Client: ${clientName}

**Fathom Summary:**
${emailData.fathom_summary}

**Fathom Action Items (auto-detected):**
${emailData.fathom_action_items}

---

**Instructions:**

1. **Action Items** Ã¢â‚¬â€� Extract ALL action items, including ones Fathom missed. Look for:
   - Explicit commitments ("I'll send that over", "We need to update...")
   - Implicit commitments (questions that need follow-up, requests for information)
   - Decisions that require implementation
   - Items deferred to future discussion

   For each action item, provide:
   {"action": "description", "owner": "consultant | client | specific_name", "priority": "high | medium | low", "deadline": "YYYY-MM-DD or next meeting or ASAP", "category": "deliverable | follow-up | decision | blocker-resolution", "context": "brief context", "clickup_list": "Active | Waiting on Client | Backlog"}

2. **Risk Flags** Ã¢â‚¬â€� Identify scope creep, stakeholder misalignment, budget/resource constraints, timeline pressure, political dynamics, engagement health indicators

3. **Key Decisions Made** Ã¢â‚¬â€� Document decisions with rationale

4. **Meeting Summary** Ã¢â‚¬â€� 3-5 sentence executive summary

5. **Next Meeting Suggestions** Ã¢â‚¬â€� What should be on the agenda

**Respond in this exact JSON structure:**
{"executive_summary": "string", "action_items": [{"action": "string", "owner": "string", "priority": "high|medium|low", "deadline": "string", "category": "string", "context": "string", "clickup_list": "Active|Waiting on Client|Backlog"}], "risk_flags": [{"type": "string", "severity": "high|medium|low", "description": "string", "recommended_action": "string"}], "key_decisions": [{"decision": "string", "rationale": "string", "impact": "string"}], "next_meeting_suggestions": ["string"], "sentiment": "positive|neutral|cautious|concerned", "engagement_health_delta": "improving|stable|declining"}`;

return [{
  json: {
    ...emailData,
    client: clientData,
    client_found: clientData.found || false,
    client_name: clientName,
    system_prompt: system_prompt,
    user_prompt: user_prompt,
    model: 'gemini-free',
    workflow_name: 'call-intelligence',
    purpose: 'analyze-meeting'
  }
}];

const analysis = $input.all()[0].json;
const meetingData = $('Merge Email + Client Data').first().json;
const parsed = typeof analysis.parsed_content === 'string'
  ? JSON.parse(analysis.parsed_content)
  : analysis.parsed_content;

const tasks = (parsed.action_items || []).map(item => ({
  name: item.action,
  description: `**Owner:** ${item.owner}\n**Priority:** ${item.priority}\n**Deadline:** ${item.deadline}\n**Category:** ${item.category}\n**Context:** ${item.context}\n\n_From meeting: ${meetingData.meeting_title} (${meetingData.meeting_date})_`,
  priority: item.priority === 'high' ? 1 : item.priority === 'medium' ? 2 : 3,
  list_type: item.clickup_list,
  due_date: item.deadline !== 'ASAP' && item.deadline !== 'next meeting' ? item.deadline : null
}));

const highRisks = (parsed.risk_flags || []).filter(r => r.severity === 'high');

const meetingNotesContent = `# ${meetingData.meeting_title}\n\n**Date:** ${meetingData.meeting_date}\n**Attendees:** ${meetingData.attendees}\n**Client:** ${meetingData.client_name}\n\n## Executive Summary\n${parsed.executive_summary}\n\n## Action Items\n${(parsed.action_items || []).map(i => `- [${i.owner}] ${i.action} (${i.priority} priority, due: ${i.deadline})`).join('\n')}\n\n## Key Decisions\n${(parsed.key_decisions || []).map(d => `- ${d.decision}: ${d.rationale}`).join('\n')}\n\n## Risk Flags\n${(parsed.risk_flags || []).map(r => `- [${r.severity}] ${r.type}: ${r.description}`).join('\n')}\n\n## Next Meeting Suggestions\n${(parsed.next_meeting_suggestions || []).map(s => `- ${s}`).join('\n')}\n\n---\n_Sentiment: ${parsed.sentiment} | Engagement Trend: ${parsed.engagement_health_delta}_`;

// Build HTML for Google Docs (Drive API upload needs HTML)
function esc(s) { return String(s).replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;'); }

const title = esc(meetingData.meeting_title);
const date = esc(meetingData.meeting_date);
const attendees = esc(meetingData.attendees);
const clientName = esc(meetingData.client_name);
const execSummary = esc(parsed.executive_summary);

const actionHtml = (parsed.action_items || []).map(i =>
  `<li><b>[${esc(i.owner)}]</b> ${esc(i.action)} (<i>${esc(i.priority)} priority, due: ${esc(i.deadline)}</i>)</li>`
).join('');

const decisionsHtml = (parsed.key_decisions || []).map(d =>
  `<li><b>${esc(d.decision)}</b>: ${esc(d.rationale)}</li>`
).join('');

const risksHtml = (parsed.risk_flags || []).map(r =>
  `<li><b>[${esc(r.severity)}] ${esc(r.type)}</b>: ${esc(r.description)}</li>`
).join('');

const suggestionsHtml = (parsed.next_meeting_suggestions || []).map(s =>
  `<li>${esc(s)}</li>`
).join('');

const meetingNotesHtml = `<html><body>
<h1>${title}</h1>
<p><b>Date:</b> ${date}<br><b>Attendees:</b> ${attendees}<br><b>Client:</b> ${clientName}</p>
<h2>Executive Summary</h2>
<p>${execSummary}</p>
<h2>Action Items</h2>
<ul>${actionHtml || '<li>None</li>'}</ul>
<h2>Key Decisions</h2>
<ul>${decisionsHtml || '<li>None</li>'}</ul>
<h2>Risk Flags</h2>
<ul>${risksHtml || '<li>None</li>'}</ul>
<h2>Next Meeting Suggestions</h2>
<ul>${suggestionsHtml || '<li>None</li>'}</ul>
<hr>
<p><i>Sentiment: ${esc(parsed.sentiment)} | Engagement Trend: ${esc(parsed.engagement_health_delta)}</i></p>
</body></html>`;

return [{
  json: {
    ...meetingData,
    analysis: parsed,
    tasks: tasks,
    high_risks: highRisks,
    has_high_risks: highRisks.length > 0,
    google_drive_folder_id: meetingData.client?.google_drive_folder_id || '',
    clickup_space_id: meetingData.client?.clickup_space_id || '90114014960',
    meeting_notes_content: meetingNotesContent,
    meeting_notes_html: meetingNotesHtml
  }
}];

// Create ClickUp task in the correct list based on AI's list_type
const task = $input.all()[0].json;
const spaceId = task.client?.clickup_space_id;

if (!spaceId) {
  throw new Error('No clickup_space_id found in client data');
}

const apiKey = 'pk_120226108_5A4ZTPSW5PUZ4YDQR9NP1LR2OPCA5BLX';

// Get folderless lists first
let lists = [];
try {
  const folderlessResponse = await this.helpers.httpRequest({
    method: 'GET',
    url: `https://api.clickup.com/api/v2/space/${spaceId}/list`,
    headers: { 'Authorization': apiKey },
    json: true
  });
  lists = folderlessResponse.lists || [];
} catch (e) {}

// If no folderless lists, check folders
if (lists.length === 0) {
  const foldersResponse = await this.helpers.httpRequest({
    method: 'GET',
    url: `https://api.clickup.com/api/v2/space/${spaceId}/folder`,
    headers: { 'Authorization': apiKey },
    json: true
  });
  const folders = foldersResponse.folders || [];
  for (const folder of folders) {
    if (folder.lists && folder.lists.length > 0) {
      lists = lists.concat(folder.lists);
    }
  }
}

if (lists.length === 0) {
  throw new Error(`No lists found in space ${spaceId} (checked folderless and folders)`);
}

// Match AI's list_type to actual list name (fuzzy match)
const listType = (task.list_type || 'active').toLowerCase();
let targetList = lists.find(l => l.name.toLowerCase().includes(listType));

// Fallback: use the first list if no match
if (!targetList) {
  targetList = lists[0];
}

// Create the task
const body = {
  name: task.name,
  description: task.description || '',
  priority: task.priority || 3
};

if (task.due_date) {
  const dueMs = new Date(task.due_date).getTime();
  if (!isNaN(dueMs)) {
    body.due_date = dueMs;
  }
}

const created = await this.helpers.httpRequest({
  method: 'POST',
  url: `https://api.clickup.com/api/v2/list/${targetList.id}/task`,
  headers: {
    'Authorization': apiKey,
    'Content-Type': 'application/json'
  },
  body: body,
  json: true
});

return [{ json: { task_id: created.id, task_name: created.name, list_name: targetList.name, url: created.url } }];

const data = $('Prepare ClickUp Tasks + Notes').first().json;
const risksHtml = data.high_risks.map(r =>
  '<p><strong>' + r.type + ':</strong> ' + r.description +
  '<br><em>Recommended:</em> ' + r.recommended_action + '</p>'
).join('');
return [{ json: {
  subject: 'Risk Flag: ' + data.client_name + ' - ' + data.meeting_title,
  body: '<h2>High-Priority Risk Detected</h2><p><strong>Client:</strong> ' + data.client_name + '</p><p><strong>Meeting:</strong> ' + data.meeting_title + '</p><hr>' + risksHtml
}}];
